const dedupeItems = $('Dedupe (seen before?)').all();
const results = [];
for (const item of $input.all()) {
  const a = item.json;
  let raw = '';
  if (typeof a.merged_response === 'string') raw = a.merged_response;
  else if (typeof a.text === 'string') raw = a.text;
  else if (Array.isArray(a.content)) raw = a.content.map(c => (c && c.text) ? c.text : '').join(' ').trim();
  raw = (raw || '').trim();

  // Strict parse: line 1 is SKIP or ENGAGE, line 2 is the nudge. No regex
  // guessing over free-form prose -- that's what let a soft-worded skip
  // ('not a great fit... let this one pass') slip through earlier.
  const lines = raw.split('\n').map((l) => l.trim()).filter(Boolean);
  const verdict = (lines[0] || '').toUpperCase();
  if (!verdict.startsWith('ENGAGE')) {
    continue;
  }
  const nudge = lines.slice(1).join(' ').trim();

  const srcIndex = item.pairedItem ? (Array.isArray(item.pairedItem) ? item.pairedItem[0].item : item.pairedItem.item) : results.length;
  const src = (dedupeItems[srcIndex] || dedupeItems[0]).json;
  const title = src.title || '(untitled post)';
  const link = src.link || '';
  const content = `📌 **${title}**${link ? '\n' + link : ''}${nudge ? '\n\n💡 ' + nudge : ''}`;
  results.push({ json: { content } });
}
return results;
